// Preparar JSON con los resultados del cálculo IFO
const data = $input.item.json;

return {
  json: {
    fecha_procesada: data.fecha_procesada,
    tipo_dia: data.tipo_dia,
    eots_procesados: data.eots_procesados,
    registros_guardados: data.registros_guardados,
    registros_actualizados: data.registros_actualizados,
    total_registros: data.total_registros,
    incumplimientos_detectados: data.incumplimientos_detectados,
    resultados: data.resultados,
    timestamp: new Date().toISOString(),
    resumen: {
      fecha: data.fecha_procesada,
      tipo_dia: data.tipo_dia,
      total_eots: data.eots_procesados,
      total_registros: data.total_registros,
      incumplimientos: data.incumplimientos_detectados,
      estado: data.incumplimientos_detectados > 0 ? 'CON_INCUMPLIMIENTOS' : 'SIN_INCUMPLIMIENTOS'
    }
  }
};

// Preparar JSON detallado con incumplimientos
const data = $input.item.json;

// Extraer todos los incumplimientos de los resultados
const incumplimientos = [];

if (data.resultados && Array.isArray(data.resultados)) {
  data.resultados.forEach(resultado => {
    if (resultado.detalle_incumplimientos && Array.isArray(resultado.detalle_incumplimientos)) {
      resultado.detalle_incumplimientos.forEach(inc => {
        incumplimientos.push({
          fecha: resultado.fecha,
          tipo_dia: resultado.tipo_dia,
          eot_nombre: inc.eot_nombre,
          eot_id: inc.eot_id,
          franja: inc.franja,
          ifo_observado: inc.ifo_observado,
          ifo_minimo: inc.ifo_minimo,
          diferencia: (inc.ifo_observado - inc.ifo_minimo).toFixed(2)
        });
      });
    }
  });
}

return {
  json: {
    fecha_procesada: data.fecha_procesada,
    tipo_dia: data.tipo_dia,
    eots_procesados: data.eots_procesados,
    registros_guardados: data.registros_guardados,
    registros_actualizados: data.registros_actualizados,
    total_registros: data.total_registros,
    incumplimientos_detectados: data.incumplimientos_detectados,
    detalle_incumplimientos: incumplimientos,
    timestamp: new Date().toISOString()
  }
};
